import React from 'react';
import { BrowserRouter as Router, Routes, Route } from 'react-router-dom';
import NavBar from './components/NavBar';
import Landing from './pages/Landing';
import './App.css';

function App() {
  return (
    <Router>
      <NavBar />
      <div style={{ paddingTop: '80px' }}> {/* Adjust for fixed navbar */}
        <Routes>
          <Route path="/" element={<Landing />} />
          <Route path="/products" element={<div><h1>Products</h1><p>Our products page</p></div>} />
          <Route path="/services" element={<div><h1>Services</h1><p>Our services page</p></div>} />
          <Route path="/about" element={<div><h1>About</h1><p>About us page</p></div>} />
          <Route path="/contact" element={<div><h1>Contact</h1><p>Contact us page</p></div>} />
        </Routes>
      </div>
    </Router>
  );
}

export default App;
